#define BLOCK_SIZE 16

__kernel void srad_cuda_1(
          __global float *E_C, 
          __global float *W_C, 
          __global float *N_C, 
          __global float *S_C,
          __global float * J_cuda, 
          __global float * C_cuda, 
          int cols, 
          int rows, 
          float q0sqr
) 
{
  int bx = get_group_id(0);
  int by = get_group_id(1);

  int tx = get_local_id(0);
  int ty = get_local_id(1);

  int index   = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

  if (index >= cols * rows) return;

  // Compute neighbor indices with boundary checks
  int row = index / cols;
  int col = index % cols;

  int index_n = (row == 0) ? index : index - cols;
  int index_s = (row == rows - 1) ? index : index + cols;
  int index_w = (col == 0) ? index : index - 1;
  int index_e = (col == cols - 1) ? index : index + 1;

  float n, w, e, s, jc, g2, l, num, den, qsqr, c;

  __local float temp[BLOCK_SIZE][BLOCK_SIZE];
  __local float temp_result[BLOCK_SIZE][BLOCK_SIZE];

  __local float north[BLOCK_SIZE][BLOCK_SIZE];
  __local float south[BLOCK_SIZE][BLOCK_SIZE];
  __local float east[BLOCK_SIZE][BLOCK_SIZE];
  __local float west[BLOCK_SIZE][BLOCK_SIZE];

  // Load neighbors into local memory
  north[ty][tx] = J_cuda[index_n]; 
  south[ty][tx] = J_cuda[index_s];
  west[ty][tx] = J_cuda[index_w];
  east[ty][tx] = J_cuda[index_e];

  temp[ty][tx] = J_cuda[index];
  barrier(CLK_LOCAL_MEM_FENCE);

  jc = temp[ty][tx];

  n  = north[ty][tx] - jc;
  s  = south[ty][tx] - jc;
  w  = west[ty][tx]  - jc; 
  e  = east[ty][tx]  - jc;

  g2 = ( n * n + s * s + w * w + e * e ) / (jc * jc);
  l = ( n + s + w + e ) / jc;

  num  = (0.5f*g2) - ((1.0f/16.0f)*(l*l));
  den  = 1.0f + (0.25f*l);
  qsqr = num/(den*den);

  den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
  c = 1.0f / (1.0f + den);

  if (c < 0.0f) {
    temp_result[ty][tx] = 0.0f;
  } else if (c > 1.0f) {
    temp_result[ty][tx] = 1.0f;
  } else {
    temp_result[ty][tx] = c;
  }

  barrier(CLK_LOCAL_MEM_FENCE);

  C_cuda[index] = temp_result[ty][tx];
  E_C[index] = e;
  W_C[index] = w;
  S_C[index] = s;
  N_C[index] = n;
}

__kernel void srad_cuda_2(
          __global float *E_C, 
          __global float *W_C, 
          __global float *N_C, 
          __global float *S_C,  
          __global float * J_cuda, 
          __global float * C_cuda, 
          int cols, 
          int rows, 
          float lambda,
          float q0sqr
) 
{
  int bx = get_group_id(0);
  int by = get_group_id(1);

  int tx = get_local_id(0);
  int ty = get_local_id(1);

  int index   = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

  if (index >= cols * rows) return;

  // Compute neighbor indices with boundary checks
  int row = index / cols;
  int col = index % cols;

  int index_s = (row == rows - 1) ? index : index + cols;
  int index_e = (col == cols - 1) ? index : index + 1;

  float cc, cn, cs, ce, cw, d_sum;

  __local float south_c[BLOCK_SIZE][BLOCK_SIZE];
  __local float east_c[BLOCK_SIZE][BLOCK_SIZE];

  __local float c_cuda_temp[BLOCK_SIZE][BLOCK_SIZE];
  __local float c_cuda_result[BLOCK_SIZE][BLOCK_SIZE];
  __local float temp[BLOCK_SIZE][BLOCK_SIZE];

  temp[ty][tx] = J_cuda[index];
  barrier(CLK_LOCAL_MEM_FENCE);

  south_c[ty][tx] = C_cuda[index_s];
  east_c[ty][tx] = C_cuda[index_e];
  barrier(CLK_LOCAL_MEM_FENCE);

  c_cuda_temp[ty][tx] = C_cuda[index];
  barrier(CLK_LOCAL_MEM_FENCE);

  cc = c_cuda_temp[ty][tx];

  cn = cc;
  cs = south_c[ty][tx];
  cw = cc;
  ce = east_c[ty][tx];

  d_sum = cn * N_C[index] + cs * S_C[index] + cw * W_C[index] + ce * E_C[index];

  c_cuda_result[ty][tx] = temp[ty][tx] + 0.25f * lambda * d_sum;

  barrier(CLK_LOCAL_MEM_FENCE);

  J_cuda[index] = c_cuda_result[ty][tx];
}
